import { Domain } from '@/constants/common';
import { useTranslate } from '@/hooks/common-hooks';
import { useLogout } from '@/hooks/login-hooks';
import { useSecondPathName } from '@/hooks/route-hook';
import {
  useFetchSystemVersion,
  useFetchUserInfo,
} from '@/hooks/user-setting-hooks';
import type { MenuProps } from 'antd';
import { Flex, Menu } from 'antd';
import React, { useEffect, useMemo } from 'react';
import { useLocation, useNavigate, useParams } from 'umi';
import {
  UserSettingBaseKey,
  UserSettingIconMap,
  UserSettingRouteKey,
} from '../constants';
import styles from './index.less';

type MenuItem = Required<MenuProps>['items'][number];

const SideBar = () => {
  const navigate = useNavigate();
  const pathName = useSecondPathName();
  const { logout } = useLogout();
  const { t } = useTranslate('setting');
  const { version, fetchSystemVersion } = useFetchSystemVersion();
  const params = useParams();
  const ulocation = useLocation();
  const { data: userInfo } = useFetchUserInfo();
  const queryParams = useMemo(() => {
    return new URLSearchParams(ulocation.search);
  }, [ulocation.search]);

  useEffect(() => {
    if (location.host !== Domain) {
      fetchSystemVersion();
    }
  }, [fetchSystemVersion]);

  function getItem(
    label: string,
    key: React.Key,
    icon?: React.ReactNode,
    children?: MenuItem[],
    type?: 'group',
  ): MenuItem {
    return {
      key,
      icon,
      children,
      label: (
        <Flex justify={'space-between'}>
          {t(label)}
          <span className={styles.version}>
            {label === 'system' && version}
          </span>
        </Flex>
      ),
      type,
    } as MenuItem;
  }

  // let items: MenuItem[] = Object.values(UserSettingRouteKey).map((value) =>
  // getItem(value, value, UserSettingIconMap[value]),

  // );

  let items: MenuItem[] = Object.values(UserSettingRouteKey).map((value) => {
    if (queryParams.get('dev') && queryParams.get('dev') == 'true') {
      return getItem(value, value, UserSettingIconMap[value]);
    } else {
      if (UserSettingRouteKey.System == value) {
        return null;
      } else if (UserSettingRouteKey.Api == value) {
        return null;
      } else if (UserSettingRouteKey.Model == value) {
        return null;
      } else if (UserSettingRouteKey.Team == value) {
        console.log('userInfouserInfo', userInfo);
        if (userInfo.is_superuser || userInfo.is_create_kownledge) {
          return getItem(value, value, UserSettingIconMap[value]);
        }
        return null;
      } else {
        return getItem(value, value, UserSettingIconMap[value]);
      }
    }
  });

  if (!queryParams.get('dev') || queryParams.get('dev') == '') {
    for (let i = items.length; i <= 0; i--) {
      if (items[i]!.key == UserSettingRouteKey.Model) {
        items.splice(i, 1);
      }
      if (items[i]!.key == UserSettingRouteKey.System) {
        items.splice(i, 1);
      }
      if (items[i]!.key == UserSettingRouteKey.Api) {
        items.splice(i, 1);
      }
    }
  }

  const handleMenuClick: MenuProps['onClick'] = ({ key }) => {
    if (key === UserSettingRouteKey.Logout) {
      logout();
    } else {
      navigate(`/${UserSettingBaseKey}/${key}`);
    }
  };

  const selectedKeys = useMemo(() => {
    return [pathName];
  }, [pathName]);

  return (
    <div>
      <section className={styles.sideBarWrapper}>
        <Menu
          selectedKeys={selectedKeys}
          mode="inline"
          items={items}
          onClick={handleMenuClick}
          style={{ width: 312 }}
        />
      </section>
    </div>
  );
};

export default SideBar;
